const cloneLabel = (option, label) => ({ ...option, label });
export function selectRouteOptions(candidates) { if (!candidates.length)
    return []; const byId = new Map(); const recommended = cloneLabel([...candidates].sort((a, b) => b.routeScore - a.routeScore)[0], 'recommended'); byId.set(recommended.id, recommended); const fastest = cloneLabel([...candidates].sort((a, b) => a.extraWalkMinutes - b.extraWalkMinutes || b.coveredItems.length - a.coveredItems.length)[0], 'fastest'); byId.set(fastest.id, fastest); const best = cloneLabel([...candidates].sort((a, b) => b.coveredItems.length - a.coveredItems.length || b.confidenceScore - a.confidenceScore)[0], 'best_coverage'); byId.set(best.id, best); return [...byId.values()].slice(0, 3); }
